targets.rawSql:
select now() as time, deadlocks::bigint as value
from pg_stat_database
where datname = current_database();

select now() as time, temp_bytes::bigint as value
from pg_stat_database
where datname = current_database();

select now() as time,
  (sum(idx_blks_hit)::float / nullif(sum(idx_blks_hit) + sum(idx_blks_read), 0)) * 100 as value
from pg_statio_user_indexes;

select now() as time,
  (sum(heap_blks_hit)::float / nullif(sum(heap_blks_hit) + sum(heap_blks_read), 0)) * 100 as value
from pg_statio_user_tables;
